// Royal Crown — regal multi-color crown with 8 tall spires and 4 jewel types.
// Z-up. Crown centered at origin; base of band at Z=0.
// Colors: gold band, crimson velvet, ruby/sapphire/emerald/amethyst gems.

const { Manifold, CrossSection } = api;

// ── helpers ─────────────────────────────────────────────────────────────────

function torus(majorR, minorR, circleSegs = 36, revolveSegs = 120) {
  const circle = CrossSection.circle(minorR, circleSegs).translate([majorR, 0]);
  return Manifold.revolve(circle, revolveSegs);
}

function cylinder(r, h, segs = 72) {
  return Manifold.cylinder(h, r, r, segs);
}

function sphere(r, segs = 40) {
  return Manifold.sphere(r, segs);
}

// Tapered cone (frustum): base radius r1, top radius r2, height h
function cone(r1, r2, h, segs = 56) {
  return Manifold.cylinder(h, r1, r2, segs);
}

// ── dimensions ───────────────────────────────────────────────────────────────

const BAND_OUTER_R = 14.5;   // outer radius of main gold band — slightly wider
const BAND_INNER_R = 12.2;   // inner bore (2.3mm wall for sturdiness)
const BAND_H       = 8.0;    // height of main band
const BEAD_MINOR   = 0.70;   // torus tube radius for ornamental bead rings

// Crown spires: 8 evenly spaced, notably tall and elegant
const N_SPIRES     = 8;
const SPIRE_BASE_R = 1.10;   // base radius at the band top
const SPIRE_MID_R  = 0.65;   // mid-spire taper (gives graceful curve effect)
const SPIRE_TIP_R  = 0.20;   // slender but printable tip
const SPIRE_H      = 13.5;   // total spire height above band top — tall and regal
const FINIAL_R     = 0.95;   // spherical finial — prominent globe at tip

// Velvet inner band (crimson, peeks above gold rim)
const VELVET_R     = BAND_INNER_R - 0.08;  // just inside the bore
const VELVET_H     = BAND_H + 2.8;          // peeks ~2.8mm above gold rim

// Jewel bezels: 8 positions (4 gem types repeating)
const N_GEMS       = 8;
const GEM_R        = 2.0;                               // prominent jewels
const GEM_ORBIT_R  = BAND_OUTER_R + GEM_R * 0.52;      // protrude outward
const GEM_Z        = BAND_H * 0.50;                     // center-height of gems
const BEZEL_WALL   = 0.28;                              // thin bezel — gem more visible
const BEZEL_H      = GEM_R * 0.85;                      // shorter so gem dome shows

// Accent beads: small gold spheres between jewels at two heights
const ACCENT_R       = 0.52;
const ACCENT_ORBIT_R = BAND_OUTER_R + 0.18;
const ACCENT_Z_MID   = BAND_H * 0.50;

// ── gold band ────────────────────────────────────────────────────────────────

const outerCyl = cylinder(BAND_OUTER_R, BAND_H);
const innerBore = cylinder(BAND_INNER_R, BAND_H + 0.4).translate([0, 0, -0.2]);
const goldBand = outerCyl.subtract(innerBore);

// ── ornate bead rings: top, bottom, and a mid decorative ring ────────────────

// Bottom bead ring — substantial and ornate
const beadRingBottom = torus(BAND_OUTER_R - BEAD_MINOR * 0.8, BEAD_MINOR)
  .translate([0, 0, BEAD_MINOR * 0.9]);

// Top bead ring
const beadRingTop = torus(BAND_OUTER_R - BEAD_MINOR * 0.8, BEAD_MINOR)
  .translate([0, 0, BAND_H - BEAD_MINOR * 0.9]);

// Inner accent ring just below the top (subtler)
const innerAccentRing = torus(BAND_OUTER_R - 1.8, BEAD_MINOR * 0.65)
  .translate([0, 0, BAND_H - BEAD_MINOR * 1.8]);

// ── crown spires + finials ────────────────────────────────────────────────────

const spireShapes = [];
for (let i = 0; i < N_SPIRES; i++) {
  const angle = (2 * Math.PI * i) / N_SPIRES;
  // Spires sit at ~midpoint between inner and outer radius
  const cx = BAND_OUTER_R * 0.86 * Math.cos(angle);
  const cy = BAND_OUTER_R * 0.86 * Math.sin(angle);
  const baseZ = BAND_H - 0.9;

  // Lower spire section: wide base tapering to mid
  const lowerSpire = cone(SPIRE_BASE_R, SPIRE_MID_R, SPIRE_H * 0.35, 48)
    .translate([cx, cy, baseZ]);

  // Upper spire section: mid tapering to very slender tip
  const upperSpire = cone(SPIRE_MID_R, SPIRE_TIP_R, SPIRE_H * 0.65, 48)
    .translate([cx, cy, baseZ + SPIRE_H * 0.35]);

  // Finial: proud sphere at the very tip
  const finialZ = baseZ + SPIRE_H + FINIAL_R * 0.55;
  const finial = sphere(FINIAL_R, 36).translate([cx, cy, finialZ]);

  // Small flared base where spire meets band — use a short wide cone as a collar
  const collar = cone(SPIRE_BASE_R * 1.55, SPIRE_BASE_R * 1.05, 0.5, 32)
    .translate([cx, cy, baseZ - 0.3]);

  spireShapes.push(lowerSpire.add(upperSpire).add(finial).add(collar));
}

const allSpires = spireShapes.reduce((acc, s) => acc.add(s));

// ── decorative arch bumps at band top (between spires) ────────────────────

// Each arch is a small dome-sphere sitting on the top edge of the band,
// between adjacent spires — adds regality to the band profile
const archBumpShapes = [];
for (let i = 0; i < N_SPIRES; i++) {
  const angle = (2 * Math.PI * i) / N_SPIRES + Math.PI / N_SPIRES; // midpoint between spires
  const archR = BAND_OUTER_R * 0.90;
  const cx = archR * Math.cos(angle);
  const cy = archR * Math.sin(angle);
  // Small teardrop arch: a slightly elongated sphere peeking above band top
  const archBump = sphere(0.65, 24).scale([1.0, 1.0, 1.3])
    .translate([cx, cy, BAND_H - 0.1]);
  archBumpShapes.push(archBump);
}
const allArchBumps = archBumpShapes.reduce((a, b) => a.add(b));

// ── combined gold geometry ─────────────────────────────────────────────────

let goldGeom = goldBand
  .add(beadRingBottom)
  .add(beadRingTop)
  .add(innerAccentRing)
  .add(allSpires)
  .add(allArchBumps);

// ── jewel bezels and gems ──────────────────────────────────────────────────

const GEM_COLORS = [
  { name: 'ruby',     color: '#cc1133' },
  { name: 'sapphire', color: '#1144cc' },
  { name: 'emerald',  color: '#118833' },
  { name: 'amethyst', color: '#771faa' },
];

const gemShapes = {};
GEM_COLORS.forEach(g => { gemShapes[g.name] = []; });
const bezelShapes = [];
const accentBeadShapes = [];

for (let i = 0; i < N_GEMS; i++) {
  const angle = (2 * Math.PI * i) / N_GEMS + Math.PI / N_GEMS; // offset from spires
  const cx = GEM_ORBIT_R * Math.cos(angle);
  const cy = GEM_ORBIT_R * Math.sin(angle);

  // Bezel: outer ring minus inner cutout — thin walls so gem is prominent
  const bezelOuter = cylinder(GEM_R + BEZEL_WALL, BEZEL_H, 36)
    .translate([cx, cy, GEM_Z - BEZEL_H * 0.5]);
  const bezelCut = cylinder(GEM_R + 0.05, BEZEL_H + 0.2, 36)
    .translate([cx, cy, GEM_Z - BEZEL_H * 0.5 - 0.1]);
  const bezel = bezelOuter.subtract(bezelCut);
  bezelShapes.push(bezel);

  // Gem: non-uniform sphere for faceted cabochon look — slightly wider than tall
  const gemType = GEM_COLORS[i % GEM_COLORS.length];
  const gem = sphere(GEM_R, 44).scale([1.05, 1.05, 0.90]).translate([cx, cy, GEM_Z]);
  gemShapes[gemType.name].push(gem);
}

// Accent beads: two between each jewel pair at alternating heights
for (let i = 0; i < N_GEMS; i++) {
  const angle0 = (2 * Math.PI * i) / N_GEMS + Math.PI / N_GEMS;
  const angle1 = (2 * Math.PI * (i + 1)) / N_GEMS + Math.PI / N_GEMS;
  // Two accent beads between each gem: at 1/3 and 2/3 of the gap
  for (let t = 1; t <= 2; t++) {
    const angle = angle0 + (angle1 - angle0) * t / 3;
    const cx = ACCENT_ORBIT_R * Math.cos(angle);
    const cy = ACCENT_ORBIT_R * Math.sin(angle);
    // Alternate bead heights slightly for more texture
    const zOff = (t % 2 === 0) ? BAND_H * 0.40 : BAND_H * 0.60;
    accentBeadShapes.push(sphere(ACCENT_R, 16).translate([cx, cy, zOff]));
  }
}

if (bezelShapes.length > 0) {
  const allBezels = bezelShapes.reduce((a, b) => a.add(b));
  goldGeom = goldGeom.add(allBezels);
}
if (accentBeadShapes.length > 0) {
  const allAccentBeads = accentBeadShapes.reduce((a, b) => a.add(b));
  goldGeom = goldGeom.add(allAccentBeads);
}

// ── velvet inner band (crimson, peeking above gold) ────────────────────────

const velvetCyl  = cylinder(VELVET_R, VELVET_H, 72);
const velvetBore = cylinder(VELVET_R - 1.1, VELVET_H + 0.2, 72).translate([0, 0, -0.1]);
const velvetBand = velvetCyl.subtract(velvetBore);

// ── assemble with labels ──────────────────────────────────────────────────────

const gemUnions = GEM_COLORS.map(g => ({
  name: g.name,
  shape: gemShapes[g.name].reduce((a, b) => a.add(b)),
  color: g.color,
}));

const fullModel = api.labeledUnion([
  { name: 'gold',     shape: goldGeom,   color: '#d4a820' },
  { name: 'velvet',   shape: velvetBand, color: '#7a1228' },
  ...gemUnions,
]);

// ── surface textures ──────────────────────────────────────────────────────────

// Subtle hammered-metal knurl on the gold band
api.surface.knurl({ amplitude: 0.13, cellWidth: 1.7, profile: 'round', quality: 0.65, label: 'gold' });

// Gentle smoothing on velvet for softness
api.surface.smooth({ iterations: 2, label: 'velvet' });

return fullModel;
